def info_processor(tipe_processor):
    """
    Mengembalikan informasi cara kerja processor kode
    """
    info = {
        "interpreter": "Menerjemahkan kode Python ______ secara langsung",
        "compiler": "Menerjemahkan seluruh program sebelum dijalankan"
    }
    return info.get(tipe_processor, "Unknown")
